import{_ as t}from"./chunks/微笑狼的公开仓库.gGdYP2E_.js";import{_ as e,o as d,c as s,a2 as i}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"자동 태그","description":"","frontmatter":{},"headers":[],"relativePath":"ko-KR/Other/auto-tagging.md","filePath":"ko-KR/Other/auto-tagging.md","lastUpdated":1781962217000}'),l={name:"ko-KR/Other/auto-tagging.md"};function o(n,a,c,p,r,h){return d(),s("div",null,[...a[0]||(a[0]=[i('<h1 id="자동-태그" tabindex="-1">자동 태그 <a class="header-anchor" href="#자동-태그" aria-label="Permalink to &quot;자동 태그&quot;">​</a></h1><p>자동 태그 기능은 다음 위치에서 설정합니다.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>시스템 설정 -&gt; 기타 설정 -&gt; 자동 태그</span></span></code></pre></div><p>이미지에 태그를 자동으로 붙여 검색, 랜덤 이미지 필터, 공개 갤러리 필터, 연령 등급 기반 접근 제어에 활용할 수 있게 합니다.</p><h2 id="할-수-있는-일" tabindex="-1">할 수 있는 일 <a class="header-anchor" href="#할-수-있는-일" aria-label="Permalink to &quot;할 수 있는 일&quot;">​</a></h2><table tabindex="0"><thead><tr><th>기능</th><th>설명</th></tr></thead><tbody><tr><td>콘텐츠 태그 생성</td><td>인물, 배경, 사물, 화풍 등 시각적 태그를 추가</td></tr><tr><td>캐릭터 태그 생성</td><td>애니메이션 이미지나 일러스트 캐릭터 판별에 유용</td></tr><tr><td>방향 태그 보완</td><td><code>landscape</code>, <code>portrait</code>, <code>square</code> 추가</td></tr><tr><td>이미지 등급 저장</td><td><code>G/S/Q/E</code> 등급 결과 저장</td></tr><tr><td>업로드 시 자동 태그</td><td>새 이미지 업로드 후 자동으로 태그 처리</td></tr><tr><td>일괄 태그</td><td>기존 이미지에 한 번에 태그 추가</td></tr></tbody></table><h2 id="먼저-준비할-것" tabindex="-1">먼저 준비할 것 <a class="header-anchor" href="#먼저-준비할-것" aria-label="Permalink to &quot;먼저 준비할 것&quot;">​</a></h2><p>접근 가능한 Hugging Face Space URL이 최소 1개 필요합니다.</p><p>권장 방식은 SmilingWolf의 <code>wd-tagger</code> Space를 본인의 Hugging Face 계정으로 복제해 사용하는 것입니다.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><p>공개 Space를 임시로 사용할 수도 있지만, 여러 사용자가 함께 쓰기 때문에 대기열이 길어지거나 느려지거나 일시적으로 사용할 수 없을 수 있습니다. 장기적으로는 본인 계정에 복제한 Space가 더 안정적입니다.</p><h2 id="space-복제하기" tabindex="-1">Space 복제하기 <a class="header-anchor" href="#space-복제하기" aria-label="Permalink to &quot;Space 복제하기&quot;">​</a></h2><ol><li>Hugging Face에 로그인합니다.</li><li><code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code>를 엽니다.</li></ol><p><img src="'+t+`" alt="SmilingWolf 공개 Space" loading="lazy"></p><ol start="3"><li>오른쪽 위 메뉴에서 <code>Duplicate this Space</code>를 선택합니다.</li><li>Space 이름은 기본값을 쓰거나 <code>wd-tagger</code>처럼 알아보기 쉽게 정합니다.</li><li>공개 범위는 <code>Public</code>으로 두는 편이 ImgBed에서 호출하기 쉽습니다.</li><li>처음에는 무료 하드웨어로 시작합니다.</li><li>빌드가 끝날 때까지 기다립니다.</li></ol><p>빌드가 완료되면 브라우저 주소를 복사해 ImgBed의 <code>Space URLs</code>에 붙여 넣습니다.</p><h2 id="설정-항목" tabindex="-1">설정 항목 <a class="header-anchor" href="#설정-항목" aria-label="Permalink to &quot;설정 항목&quot;">​</a></h2><table tabindex="0"><thead><tr><th>항목</th><th>권장값</th></tr></thead><tbody><tr><td><code>Space URLs</code></td><td>준비한 Space URL을 한 줄에 하나씩 입력</td></tr><tr><td>대상 폴더</td><td>전체 처리면 비워 두고, 특정 폴더만 처리하려면 선택</td></tr><tr><td>인식 모델</td><td>기본은 <code>wd-swinv2-tagger-v3</code></td></tr><tr><td>일반 태그 임계값</td><td>보통 <code>0.35</code> 전후로 시작</td></tr><tr><td>캐릭터 태그 임계값</td><td>오인식을 줄이려면 <code>0.85</code> 전후</td></tr><tr><td><code>MCut</code></td><td>처음에는 끄고 테스트</td></tr><tr><td>업로드 시 자동 태그</td><td>새 이미지에도 적용하려면 켜기</td></tr></tbody></table><p>태그가 너무 많으면 일반 태그 임계값을 조금 올리고, 너무 적으면 조금 낮춥니다.</p><h2 id="일괄-태그" tabindex="-1">일괄 태그 <a class="header-anchor" href="#일괄-태그" aria-label="Permalink to &quot;일괄 태그&quot;">​</a></h2><ol><li><code>Space URLs</code>를 입력합니다.</li><li>대상 폴더를 선택합니다.</li><li>태그 작업을 시작합니다.</li><li>진행률이 끝날 때까지 기다립니다.</li></ol><p>대상 폴더가 비어 있으면 전체 폴더를 처리합니다.</p><h2 id="업로드-시-자동-태그" tabindex="-1">업로드 시 자동 태그 <a class="header-anchor" href="#업로드-시-자동-태그" aria-label="Permalink to &quot;업로드 시 자동 태그&quot;">​</a></h2><p>이 옵션을 켜면 새로 업로드한 이미지가 자동으로 태그 처리 흐름에 들어갑니다.</p><p>Space가 대기 중이어도 업로드 자체는 먼저 끝날 수 있고, 태그 처리는 뒤에서 계속 진행됩니다.</p><h2 id="자주-묻는-점" tabindex="-1">자주 묻는 점 <a class="header-anchor" href="#자주-묻는-점" aria-label="Permalink to &quot;자주 묻는 점&quot;">​</a></h2><h3 id="왜-내-space를-복제해서-쓰나요" tabindex="-1">왜 내 Space를 복제해서 쓰나요? <a class="header-anchor" href="#왜-내-space를-복제해서-쓰나요" aria-label="Permalink to &quot;왜 내 Space를 복제해서 쓰나요?&quot;">​</a></h3><p>공개 Space는 많은 사용자가 함께 사용합니다. 본인 Space는 주로 내 ImgBed 사이트에서만 호출하므로 더 빠르고 안정적입니다.</p><h3 id="태그가-영어로-나오는-것이-정상인가요" tabindex="-1">태그가 영어로 나오는 것이 정상인가요? <a class="header-anchor" href="#태그가-영어로-나오는-것이-정상인가요" aria-label="Permalink to &quot;태그가 영어로 나오는 것이 정상인가요?&quot;">​</a></h3><p>정상입니다. SmilingWolf 계열 모델은 영어 태그를 반환합니다. 이 태그는 검색, 필터, 랜덤 이미지 API, 공개 갤러리에서 사용됩니다.</p><h3 id="등급-태그는-어디에-쓰나요" tabindex="-1">등급 태그는 어디에 쓰나요? <a class="header-anchor" href="#등급-태그는-어디에-쓰나요" aria-label="Permalink to &quot;등급 태그는 어디에 쓰나요?&quot;">​</a></h3><p>보안 설정의 접근 모드와 함께 사용합니다. 방문자 접근을 연령 등급으로 제한할 때 공개 갤러리와 랜덤 이미지 기능이 해당 규칙을 따릅니다.</p><h2 id="빠른-절차" tabindex="-1">빠른 절차 <a class="header-anchor" href="#빠른-절차" aria-label="Permalink to &quot;빠른 절차&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hugging Face 로그인</span></span>
<span class="line"><span>-&gt; SmilingWolf/wd-tagger 열기</span></span>
<span class="line"><span>-&gt; Duplicate this Space</span></span>
<span class="line"><span>-&gt; 빌드 완료 대기</span></span>
<span class="line"><span>-&gt; Space URL 복사</span></span>
<span class="line"><span>-&gt; ImgBed의 Space URLs에 입력</span></span>
<span class="line"><span>-&gt; 모델과 임계값 설정</span></span>
<span class="line"><span>-&gt; 일괄 태그 시작 또는 업로드 시 자동 태그 켜기</span></span></code></pre></div>`,34)])])}const m=e(l,[["render",o]]);export{b as __pageData,m as default};
